1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const FP_EPSILON = 1e-9;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = { type: string; cursed?: boolean; enchantment?: number };
13	type Customer = { yearsWithMHPCO: number };
14	type Damage = { itemType: string; amount: number };
15	type Incident = { cause: string; damages: Damage[] };
16	type QuoteStep = { op: "quote"; items: Item[] };
17	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
18	type Step = QuoteStep | ClaimStep;
19	type Scenario = { customer: Customer; steps: Step[] };
20	
21	const DEDUCTIBLE = 100;
22	const INSURANCE_VALUE_MULTIPLIER = 10;
23	const CAP_MULTIPLIER = 2;
24	
25	const insuranceValue = (type: string): number =>
26	  BASE_PREMIUM[type] * INSURANCE_VALUE_MULTIPLIER;
27	
28	const sum = (numbers: number[]): number =>
29	  numbers.reduce((acc, n) => acc + n, 0);
30	
31	// round up to whole G in MHPCO's favor, using epsilon to fight FP error
32	const roundUpInMHPCOFavor = (amount: number): number =>
33	  Math.ceil(amount - FP_EPSILON);
34	
35	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	const COMPONENT_BLOCK_SIZE = 3;
37	const COMPONENT_BLOCK_PRICE = 60;
38	
39	const countByType = (items: Item[]): Map<string, number> =>
40	  items.reduce(
41	    (acc, item) => acc.set(item.type, (acc.get(item.type) ?? 0) + 1),
42	    new Map<string, number>(),
43	  );
44	
45	const typeGroupPremium = (type: string, count: number): number =>
46	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE
47	    ? COMPONENT_BLOCK_PRICE
48	    : count * BASE_PREMIUM[type];
49	
50	const itemsBasePremium = (items: Item[]): number =>
51	  sum(
52	    Array.from(countByType(items), ([type, count]) =>
53	      typeGroupPremium(type, count),
54	    ),
55	  );
56	
57	type Rule<T> = { applies: (subject: T) => boolean; rate: number };
58	
59	const sumApplicableRates = <T>(base: number, subject: T, rules: Rule<T>[]): number =>
60	  sum(rules.map((rule) => (rule.applies(subject) ? base * rule.rate : 0)));
61	
62	const CURSE_SURCHARGE_RATE = 0.5;
63	const HIGH_ENCHANTMENT_RATE = 0.3;
64	const HIGH_ENCHANTMENT_THRESHOLD = 5;
65	
66	const SURCHARGE_RULES: Rule<Item>[] = [
67	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE_RATE },
68	  {
69	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
70	    rate: HIGH_ENCHANTMENT_RATE,
71	  },
72	];
73	
74	const itemSurcharge = (item: Item): number =>
75	  sumApplicableRates(BASE_PREMIUM[item.type], item, SURCHARGE_RULES);
76	
77	const itemSurcharges = (items: Item[]): number =>
78	  sum(items.map(itemSurcharge));
79	
80	const LOYALTY_DISCOUNT_RATE = 0.2;
81	const LOYALTY_YEARS_THRESHOLD = 2;
82	const FOLLOWUP_DISCOUNT_RATE = 0.15;
83	
84	type PolicyContext = { customer: Customer; isFollowup: boolean };
85	
86	const POLICY_DISCOUNT_RULES: Rule<PolicyContext>[] = [
87	  {
88	    applies: (ctx) => ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
89	    rate: -LOYALTY_DISCOUNT_RATE,
90	  },
91	  { applies: (ctx) => ctx.isFollowup, rate: -FOLLOWUP_DISCOUNT_RATE },
92	];
93	
94	const policyModifiers = (policyBase: number, ctx: PolicyContext): number =>
95	  policyBase * FIRST_INSURANCE_RATE +
96	  sumApplicableRates(policyBase, ctx, POLICY_DISCOUNT_RULES);
97	
98	const assertKnownItemType = (item: Item): void => {
99	  if (!(item.type in BASE_PREMIUM)) {
100	    throw new Error(`unknown item type: ${item.type}`);
101	  }
102	};
103	
104	const quote = ({ items }: QuoteStep, ctx: PolicyContext): { premium: number } => {
105	  items.forEach(assertKnownItemType);
106	  const policyBase = itemsBasePremium(items);
107	  const total =
108	    policyBase +
109	    itemSurcharges(items) +
110	    policyModifiers(policyBase, ctx) +
111	    PROCESSING_FEE;
112	  return { premium: roundUpInMHPCOFavor(total) };
113	};
114	
115	type Policy = { items: Item[]; remainingCap: number };
116	
117	const policyInsuranceSum = (items: Item[]): number =>
118	  sum(items.map((item) => insuranceValue(item.type)));
119	
120	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
121	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
122	const FULL_PAYOUT_RATE = 1;
123	
124	const payoutRate = (item: Item): number =>
125	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
126	    ? HIGH_ENCHANTMENT_PAYOUT_RATE
127	    : FULL_PAYOUT_RATE;
128	
129	const assertNonNegativeDamage = (damage: Damage): void => {
130	  if (damage.amount < 0) {
131	    throw new Error(`negative damage amount: ${damage.amount}`);
132	  }
133	};
134	
135	const damagePayout = (damage: Damage, item: Item): number => {
136	  assertNonNegativeDamage(damage);
137	  return Math.max(0, damage.amount * payoutRate(item) - DEDUCTIBLE);
138	};
139	
140	const openPolicy = (items: Item[]): Policy => ({
141	  items,
142	  remainingCap: policyInsuranceSum(items) * CAP_MULTIPLIER,
143	});
144	
145	const processQuote = (
146	  step: QuoteStep,
147	  customer: Customer,
148	  policies: Policy[],
149	) => {
150	  const result = quote(step, { customer, isFollowup: policies.length > 0 });
151	  policies.push(openPolicy(step.items));
152	  return result;
153	};
154	
155	const findInsuredItem = (policy: Policy, itemType: string): Item => {
156	  const item = policy.items.find((i) => i.type === itemType);
157	  if (item === undefined) {
158	    throw new Error(`item type not in policy: ${itemType}`);
159	  }
160	  return item;
161	};
162	
163	const uncappedClaimPayout = (policy: Policy, incident: Incident): number =>
164	  sum(incident.damages.map((d) => damagePayout(d, findInsuredItem(policy, d.itemType))));
165	
166	const processClaim = (step: ClaimStep, policies: Policy[]) => {
167	  const policy = policies[step.policy];
168	  const payout = Math.min(uncappedClaimPayout(policy, step.incident), policy.remainingCap);
169	  policy.remainingCap -= payout;
170	  return { payout, remainingCap: policy.remainingCap };
171	};
172	
173	export const runScenario = (input: unknown): unknown => {
174	  const { customer, steps } = input as Scenario;
175	  const policies: Policy[] = [];
176	  const results = steps.map((step) =>
177	    step.op === "quote"
178	      ? processQuote(step, customer, policies)
179	      : processClaim(step, policies),
180	  );
181	  return { results };
182	};
